var surah045 = {
  number: 45,
  nameArabic: "Al-Jathiyah",
  nameEnglish: "Al-Jathiyah",
  meaning: "The Crouching",
  totalAyahs: 37,
  ayahs: [
    { number: 1, arabic: "حمٓ", transliteration: "Hameem", transliterationB: "Haa-Meeem", english: "Ha-Mim", romanUrdu: "Haa Meem" },
    { number: 2, arabic: "تَنزِيلُ ٱلْكِتَٰبِ مِنَ ٱللَّهِ ٱلْعَزِيزِ ٱلْحَكِيمِ", transliteration: "Tanzeelu alkitabi mina Allahi alAAazeezi alhakeemi", transliterationB: "Tanzeelul Kitaabi minal laahil 'Azeezil Hakeem", english: "The revelation of the Book is from Allah the Exalted in Power, Full of Wisdom", romanUrdu: "Is kitaab ka nuzul Allah ki taraf se hai jo zabardast aur Hakeem hai" },
    { number: 3, arabic: "إِنَّ فِى ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ لَءَايَٰتٍۢ لِّلْمُؤْمِنِينَ", transliteration: "Inna fee alssamawati waalardi laayatin lilmumineena", transliterationB: "Innaa fis samaawaati wal ardi la Aayaatil lilmu'mineen", english: "Verily in the heavens and the earth, are Signs for those who believe", romanUrdu: "Haqeeqat yeh hai ke aasmaano aur zameen mein beshumaar nishaniyan hain iman laney walon ke liye" },
    { number: 4, arabic: "وَفِى خَلْقِكُمْ وَمَا يَبُثُّ مِن دَآبَّةٍ ءَايَٰتٌۭ لِّقَوْمٍۢ يُوقِنُونَ", transliteration: "Wafee khalqikum wama yabuththu min dabbatin ayatun liqawmin yooqinoona", transliterationB: "Wa fee khalaqikum wa maa yabussu min daaabbatin Aayaatul liqawminy-yooqinoon", english: "And in the creation of yourselves and the fact that animals are scattered (through the earth), are Signs for those of assured Faith", romanUrdu: "Aur tumhari apni paidaish mein, aur un haiwanaat(janwaron) mein jinko Allah (zameen mein) phayla raha hai, badi nishaniyan hain un logon ke liye jo yaqeen laney waley hain" },
    { number: 5, arabic: "وَٱخْتِلَٰفِ ٱلَّيْلِ وَٱلنَّهَارِ وَمَآ أَنزَلَ ٱللَّهُ مِنَ ٱلسَّمَآءِ مِن رِّزْقٍۢ فَأَحْيَا بِهِ ٱلْأَرْضَ بَعْدَ مَوْتِهَا وَتَصْرِيفِ ٱلرِّيَٰحِ ءَايَٰتٌۭ لِّقَوْمٍۢ يَعْقِلُونَ", transliteration: "Waikhtilafi allayli waalnnahari wama anzala Allahu mina alssamai min rizqin faahya bihi alarda baAAda mawtiha watasreefi alrriyahi ayatun liqawmin yaAAqiloona", transliterationB: "Wakhtilaafil laili wannahaari wa maaa anzalal laahu minas samaaa'i mir rizqin fa ahyaa bihil arda ba'da mawtihaa wa tasreefir riyaahi Aayaatul liqawminy ya'qiloon", english: "And in the alternation of Night and Day, and the fact that Allah sends down Sustenance from the sky, and revives therewith the earth after its death, and in the change of the winds,- are Signs for those that are wise", romanUrdu: "Aur shab-o-roz (night and day) ke farq o ikhtilaf mein, aur us rizq mein jisey Allah aasmaan se nazil farmata hai phir uske zariye se murda zameen ko jila uthata hai, aur hawaon ki gardish mein bahut nishaniyan hain un logon ke liye jo aqal se kaam letey hain" },
    { number: 6, arabic: "تِلْكَ ءَايَٰتُ ٱللَّهِ نَتْلُوهَا عَلَيْكَ بِٱلْحَقِّ ۖ فَبِأَىِّ حَدِيثٍۭ بَعْدَ ٱللَّهِ وَءَايَٰتِهِۦ يُؤْمِنُونَ", transliteration: "Tilka ayatu Allahi natlooha AAalayka bialhaqqi fabiayyi hadeethin baAAda Allahi waayatihi yuminoona", transliterationB: "Tilka Aayatul laahi natloohaa 'alika bilhaqq, fabiayyi hadeesim ba'dal laahi wa Aayaatihee yu'minoon", english: "Such are the Signs of Allah, which We rehearse to thee in Truth; then in what exposition will they believe after (rejecting) Allah and His Signs", romanUrdu: "Yeh Allah ki nishaniyan hain jinhein hum tumhare saamne theek theek bayan kar rahey hain. Ab aakhir Allah aur uski aayat ke baad aur kaunsi baat hai jispar yeh log imaan layenge" },
    { number: 7, arabic: "وَيْلٌۭ لِّكُلِّ أَفَّاكٍ أَثِيمٍۢ", transliteration: "Waylun likulli affakin atheemin", transliterationB: "Wailul likulli affaakin aseem", english: "Woe to each sinful dealer in Falsehoods", romanUrdu: "Tabahi hai har us jhoote badh amal shaks ke liye" },
    { number: 8, arabic: "يَسْمَعُ ءَايَٰتِ ٱللَّهِ تُتْلَىٰ عَلَيْهِ ثُمَّ يُصِرُّ مُسْتَكْبِرًۭا كَأَن لَّمْ يَسْمَعْهَا ۖ فَبَشِّرْهُ بِعَذَابٍ أَلِيمٍۢ", transliteration: "YasmaAAu ayati Allahi tutla AAalayhi thumma yusirru mustakbiran kaan lam yasmaAAha fabashshirhu biAAathabin aleemin", transliterationB: "Yasma'u Aayaatil laahi tutlaa 'alaihi summa yusirru mustakbiran ka-al lam yasma'haa fabashshirhu bi'azaabin aleem", english: "He hears the Signs of Allah rehearsed to him, yet is obstinate and lofty, as if he had not heard them: then announce to him a Penalty Grievous", romanUrdu: "Jiske saamne Allah ki aayat padi jaati hain, aur woh unko sunta hai, phir puray istakbar ke saath apne kufr par is tarah ada rehta hai goya usne unko suna hi nahin. Aise shaks ko dardnaak azaab ka musda suna do" },
    { number: 9, arabic: "وَإِذَا عَلِمَ مِنْ ءَايَٰتِنَا شَيْـًٔا ٱتَّخَذَهَا هُزُوًا ۚ أُو۟لَٰٓئِكَ لَهُمْ عَذَابٌۭ مُّهِينٌۭ", transliteration: "Waitha AAalima min ayatina shayan ittakhathaha huzuwan olaika lahum AAathabun muheenun", transliterationB: "Wa izaa 'alima min Aayaatinaa shai'anit takhazahaa huzuwaa; ulaaa'ika lahum 'azaabum muheen", english: "And when he learns something of Our Signs, he takes them in jest: for such there will be a humiliating Penalty", romanUrdu: "Hamari aayat mein se koi baat jab uske ilm mein aati hai to woh unka mazaak bana leta hain. Aisey sab logon ke liye zillat ka azaab hai" },
    { number: 10, arabic: "مِّن وَرَآئِهِمْ جَهَنَّمُ ۖ وَلَا يُغْنِى عَنْهُم مَّا كَسَبُوا۟ شَيْـًۭٔا وَلَا مَا ٱتَّخَذُوا۟ مِن دُونِ ٱللَّهِ أَوْلِيَآءَ ۖ وَلَهُمْ عَذَابٌ عَظِيمٌ", transliteration: "Min waraihim jahannamu wala yughnee AAanhum ma kasaboo shayan wala ma ittakhathoo min dooni Allahi awliyaa walahum AAathabun AAatheemun", transliterationB: "Minw waraaa'ihim Jahannamu wa laa yughnee 'anhum maa kasaboo shai'anw wa laa mat takhazoo min doonil laahi awliyaaa'a wa lahum 'azaabun 'azeem", english: "In front of them is Hell: and of no profit to them is anything they may have earned, nor any protectors they may have taken to themselves besides Allah: for them is a tremendous Penalty", romanUrdu: "Unke aage jahannum hai. Jo kuch bhi unhone duniya mein kamaya hai usmein se koi cheez unke kisi kaam na aayegi. Na unke woh sarparast hi unke liye kuch kar sakenge jinhein Allah ko chodh kar unhon ne apna wali bana rakkha hai. Unke liye bada azaab hai" },
    { number: 11, arabic: "هَٰذَا هُدًۭى ۖ وَٱلَّذِينَ كَفَرُوا۟ بِـَٔايَٰتِ رَبِّهِمْ لَهُمْ عَذَابٌۭ مِّن رِّجْزٍ أَلِيمٌ", transliteration: "Hatha hudan waallatheena kafaroo biayati rabbihim lahum AAathabun min rijzin aleemin", transliterationB: "Haazaa hudanw wal lazeena kafaroo bi aayaati Rabbihim lahum 'azaabum mir rijzin aleem", english: "This is (true) Guidance and for those who reject the Signs of their Lord, is a grievous Penalty of abomination", romanUrdu: "Yeh Quran sarasar hidayat hai, aur un logon ke liye balaa ka dardnaak azaab hai jinhon ne apne Rubb ki aayat ko maan-ne se inkar kiya" },
    { number: 12, arabic: "۞ ٱللَّهُ ٱلَّذِى سَخَّرَ لَكُمُ ٱلْبَحْرَ لِتَجْرِىَ ٱلْفُلْكُ فِيهِ بِأَمْرِهِۦ وَلِتَبْتَغُوا۟ مِن فَضْلِهِۦ وَلَعَلَّكُمْ تَشْكُرُونَ", transliteration: "Allahu allathee sakhkhara lakumu albahra litajriya alfulku feehi biamrihi walitabtaghoo min fadlihi walaAAallakum tashkuroona", transliterationB: "Allaahul lazee sahkhara lakumul bahra litajriyal fulku feehi bi amrihee wa litabtaghoo min fadlihee wa la'allakum tashkuroon", english: "It is Allah Who has subjected the sea to you, that ships may sail through it by His command, that ye may seek of his Bounty, and that ye may be grateful", romanUrdu: "Woh Allah hi to hai jisne tumhare liye samandar ko musakkhar kiya taa-ke uske hukum se kashtiyan usmein chalein aur tum uska fazal talash karo aur shukar guzar ho" },
    { number: 13, arabic: "وَسَخَّرَ لَكُم مَّا فِى ٱلسَّمَٰوَٰتِ وَمَا فِى ٱلْأَرْضِ جَمِيعًۭا مِّنْهُ ۚ إِنَّ فِى ذَٰلِكَ لَءَايَٰتٍۢ لِّقَوْمٍۢ يَتَفَكَّرُونَ", transliteration: "Wasakhkhara lakum ma fee alssamawati wama fee alardi jameeAAan minhu inna fee thalika laayatin liqawmin yatafakkaroona", transliterationB: "Wa sakhkhara lakum maa fis samaawaati wa maa fil ardi jamee'am minh; inna feezaalika la Aayaatil liqawminy yatafakkaroon", english: "And He has subjected to you, as from Him, all that is in the heavens and on earth: Behold, in that are Signs indeed for those who reflect", romanUrdu: "Usne zameen aur aasmaano ki saari hi cheezon ko tumhare liye musakkhar kardiya, sab kuch apne paas se. Ismein badi nishaniyan hai un logon ke lye jo gaur o fikr karne wale hain" },
    { number: 14, arabic: "قُل لِّلَّذِينَ ءَامَنُوا۟ يَغْفِرُوا۟ لِلَّذِينَ لَا يَرْجُونَ أَيَّامَ ٱللَّهِ لِيَجْزِىَ قَوْمًۢا بِمَا كَانُوا۟ يَكْسِبُونَ", transliteration: "Qul lillatheena amanoo yaghfiroo lillatheena la yarjoona ayyama Allahi liyajziya qawman bima kanoo yaksiboona", transliterationB: "Qul lillazeena aamanoo yaghfiroo lillazeena laa yarjoona ayyaamal laahi liyajziya qawmam bimaa kaanoo yaksiboon", english: "Tell those who believe, to forgive those who do not look forward to the Days of Allah: It is for Him to recompense (for good or ill) each People according to what they have earned", romanUrdu: "(Aey Nabi) imaan laney walon se kehdo ke jo log Allah ki taraf se bure din aane ka koi andesha nahin rakhte, unki harakaton par darguzar se kaam lein taa-ke Allah khud ek giroh ko uski kamayi ka badla de" },
    { number: 15, arabic: "مَنْ عَمِلَ صَٰلِحًۭا فَلِنَفْسِهِۦ ۖ وَمَنْ أَسَآءَ فَعَلَيْهَا ۖ ثُمَّ إِلَىٰ رَبِّكُمْ تُرْجَعُونَ", transliteration: "Man AAamila salihan falinafsihi waman asaa faAAalayha thumma ila rabbikum turjaAAoona", transliterationB: "Maa 'amila saalihan falinafsihee wa man asaaa'a fa'alaihaa summa ilaa Rabbikum turja'oon", english: "If any one does a righteous deed, it ensures to the benefit of his own soul; if he does evil, it works against (his own soul). In the end will ye (all) be brought back to your Lord", romanUrdu: "Jo koi neik amal karega apne hi liye karega, aur jo burai karega woh aap hi uska khumyaza (consequence) bhugtega. Phir jaana to sabko apne Rubb hi ki taraf hai" },
    { number: 16, arabic: "وَلَقَدْ ءَاتَيْنَا بَنِىٓ إِسْرَٰٓءِيلَ ٱلْكِتَٰبَ وَٱلْحُكْمَ وَٱلنُّبُوَّةَ وَرَزَقْنَٰهُم مِّنَ ٱلطَّيِّبَٰتِ وَفَضَّلْنَٰهُمْ عَلَى ٱلْعَٰلَمِينَ", transliteration: "Walaqad atayna banee israeela alkitaba waalhukma waalnnubuwwata warazaqnahum mina alttayyibati wafaddalnahum AAala alAAalameena", transliterationB: "Wa laqad aatainaa Baneee Israaa'eelal Kitaaba walhukma wan Nubuwwata wa razaqnaahum minat taiyibaati wa faddalnaahum;alal 'aalameen", english: "We did aforetime grant to the Children of Israel the Book the Power of Command, and Prophethood; We gave them, for Sustenance, things good and pure; and We favoured them above the nations", romanUrdu: "Issey pehle bani Israel ko humne kitaab aur hukum aur nabuwat ata ki thi, unko humne umda samaan e zeist se nawaza, duniya bhar ke logon par unhein fazilat ata ki" },
    { number: 17, arabic: "وَءَاتَيْنَٰهُم بَيِّنَٰتٍۢ مِّنَ ٱلْأَمْرِ ۖ فَمَا ٱخْتَلَفُوٓا۟ إِلَّا مِنۢ بَعْدِ مَا جَآءَهُمُ ٱلْعِلْمُ بَغْيًۢا بَيْنَهُمْ ۚ إِنَّ رَبَّكَ يَقْضِى بَيْنَهُمْ يَوْمَ ٱلْقِيَٰمَةِ فِيمَا كَانُوا۟ فِيهِ يَخْتَلِفُونَ", transliteration: "Waataynahum bayyinatin mina alamri fama ikhtalafoo illa min baAAdi ma jaahumu alAAilmu baghyan baynahum inna rabbaka yaqdee baynahum yawma alqiyamati feema kanoo feehi yakhtalifoona", transliterationB: "Wa aatainaahum baiyinaatim minal amri famakh talafooo illaa mim ba'di maa jaaa'ahumul 'ilmu baghyam bainahum; inna Rabbaka yaqdee bainahum Yawmal Qiyaamati feemaa kaanoo feehi yakhtalifoon", english: "And We granted them Clear Signs in affairs (of Religion): it was only after knowledge had been granted to them that they fell into schisms, through insolent envy among themselves. Verily thy Lord will judge between them on the Day of Judgment as to those matters in which they set up differences", romanUrdu: "Aur deen ke maamle mein unhein wazeh hidayat de di.Phir jo ikhtilaf unke darmiyan runama hua woh (nawaqifiyat ki wajah se nahin balke) ilm aa jaaney ke baad hua aur us bina par hua ke woh aapas mein ek dusre par zyadati karna chahte thay. Allah qayamat ke roz un maamlaat ka faisla farmadega jinmein woh ikhtilaf karte rahey hain" },
    { number: 18, arabic: "ثُمَّ جَعَلْنَٰكَ عَلَىٰ شَرِيعَةٍۢ مِّنَ ٱلْأَمْرِ فَٱتَّبِعْهَا وَلَا تَتَّبِعْ أَهْوَآءَ ٱلَّذِينَ لَا يَعْلَمُونَ", transliteration: "Thumma jaAAalnaka AAala shareeAAatin mina alamri faittabiAAha wala tattabiAA ahwaa allatheena la yaAAlamoona", transliterationB: "Summa ja'alnaaka 'alaa sharee'atim minal amri fattabi'haa wa laa tattabi'ahwaaa'al-lazeena laa ya'lamoon", english: "Then We put thee on the (right) Way of Religion: so follow thou that (Way), and follow not the desires of those who know not", romanUrdu: "Iske baad aey Nabi humne tumko din ke maamley mein ek saaf shah-raah(shariyat) par qayam kiya hai. Lihaza tum usi par chalo aur un logon ki khwahishat ka ittiba na karo jo ilm nahin rakhte" },
    { number: 19, arabic: "إِنَّهُمْ لَن يُغْنُوا۟ عَنكَ مِنَ ٱللَّهِ شَيْـًۭٔا ۚ وَإِنَّ ٱلظَّٰلِمِينَ بَعْضُهُمْ أَوْلِيَآءُ بَعْضٍۢ ۖ وَٱللَّهُ وَلِىُّ ٱلْمُتَّقِينَ", transliteration: "Innahum lan yughnoo AAanka mina Allahi shayan wainna alththalimeena baAAduhum awliyao baAAdin waAllahu waliyyu almuttaqeena", transliterationB: "Innahum lany yughnoo 'anka minal laahi shai'aa; wa innaz zaalimeena ba'duhum awliyaaa'u ba'dinw wallaahu waliyyul muttaqeen", english: "They will be of no use to thee in the sight of Allah: it is only Wrong-doers (that stand as) protectors, one to another: but Allah is the Protector of the Righteous", romanUrdu: "Allah ke muqable mein woh tumhare kuch bhi kaam nahin aa sakte. Zaalim log ek dusre ke saathi hain, aur muttaaqiyon ka saathi Allah hai" },
    { number: 20, arabic: "هَٰذَا بَصَٰٓئِرُ لِلنَّاسِ وَهُدًۭى وَرَحْمَةٌۭ لِّقَوْمٍۢ يُوقِنُونَ", transliteration: "Hatha basairu lilnnasi wahudan warahmatun liqawmin yooqinoona", transliterationB: "Haazaa basaaa'iru linnaasi wa hudanw wa rahmatul liqawminy yooqinoon", english: "These are clear evidences to men and a Guidance and Mercy to those of assured Faith", romanUrdu: "Yeh basirat ki roshiniyan hain sab logon ke liye aur hidayat aur rehmat un logon ke liye jo yaqeen layein" },
    { number: 21, arabic: "أَمْ حَسِبَ ٱلَّذِينَ ٱجْتَرَحُوا۟ ٱلسَّيِّـَٔاتِ أَن نَّجْعَلَهُمْ كَٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ سَوَآءًۭ مَّحْيَاهُمْ وَمَمَاتُهُمْ ۚ سَآءَ مَا يَحْكُمُونَ", transliteration: "Am hasiba allatheena ijtarahoo alssayyiati an najAAalahum kaallatheena amanoo waAAamiloo alssalihati sawaan mahyahum wamamatuhum saa ma yahkumoona", transliterationB: "Am hasibal lazeenaj tarahus saiyiaati an naj'alahum kallazeena aamanoo wa 'amilu saalihaati sawaaa'am mahyaahum wa mamaatuhum; saaa'a maa yahkumoon", english: "What! Do those who seek after evil ways think that We shall hold them equal with those who believe and do righteous deeds,- that equal will be their life and their death? Ill is the judgment that they make", romanUrdu: "Kya woh log jinhon ne buraiyon ka irtiqaab kiya hai yeh samjhe baithay hain ke hum unhein aur imaan laney walon aur neik amal karne walon ko ek jaisa kardenge ke inka jeena aur marna yaksan ho jaye? Bahut burey hukum hain jo yeh log lagate hain" },
    { number: 22, arabic: "وَخَلَقَ ٱللَّهُ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضَ بِٱلْحَقِّ وَلِتُجْزَىٰ كُلُّ نَفْسٍۭ بِمَا كَسَبَتْ وَهُمْ لَا يُظْلَمُونَ", transliteration: "Wakhalaqa Allahu alssamawati waalarda bialhaqqi walitujza kullu nafsin bima kasabat wahum la yuthlamoona", transliterationB: "Wa khalaqal laahus samaawaati wal arda bilhaqqi wa litujzaa kullu nafsim bimaa kasabat wa hum laa yuzlamoon", english: "Allah created the heavens and the earth for just ends, and in order that each soul may find the recompense of what it has earned, and none of them be wronged", romanUrdu: "Allah ne to Aasmaano aur zameen ko barhaqq paida kiya hai aur is liye kiya hai ke har mutannafis ko uski kamayi ka badla diya jaye. Logon par zulm hargiz na kiya jayega" },
    { number: 23, arabic: "أَفَرَءَيْتَ مَنِ ٱتَّخَذَ إِلَٰهَهُۥ هَوَىٰهُ وَأَضَلَّهُ ٱللَّهُ عَلَىٰ عِلْمٍۢ وَخَتَمَ عَلَىٰ سَمْعِهِۦ وَقَلْبِهِۦ وَجَعَلَ عَلَىٰ بَصَرِهِۦ غِشَٰوَةًۭ فَمَن يَهْدِيهِ مِنۢ بَعْدِ ٱللَّهِ ۚ أَفَلَا تَذَكَّرُونَ", transliteration: "Afaraayta mani ittakhatha ilahahu hawahu waadallahu Allahu AAala AAilmin wakhatama AAala samAAihi waqalbihi wajaAAala AAala basarihi ghishawatan faman yahdeehi min baAAdi Allahi afala tathakkaroona", transliterationB: "Afara'ayta manit takhaza ilaahahoo hawaahu wa adal lahul laahu 'alaa 'ilminw wa khatama 'alaa sam'ihee wa qalbihee wa ja'ala 'alaa basarihee ghishaawatan famany yahdeehi mim ba'dil laah; afalaa tazakkaroon", english: "Then seest thou such a one as takes as his god his own vain desire? Allah has, knowing (him as such), left him astray, and sealed his hearing and his heart (and understanding), and put a cover on his sight. Who, then, will guide him after Allah (has withdrawn Guidance)? Will ye not then receive admonition", romanUrdu: "Phir kya tumne kabhi us shaks ke haal par bhi gaur kiya jisne apni khwahish e nafs ko apna khuda bana liya aur Allah ne ilm ke bawajood usey gumrahi mein phenk diya aur uske dil aur kaano (ears) par mohar laga di aur uski aankhon par purdah daal diya? Allah ke baad ab aur kaun hai jo usey hidayat de? Kya tum log koi sabaq nahin letay" },
    { number: 24, arabic: "وَقَالُوا۟ مَا هِىَ إِلَّا حَيَاتُنَا ٱلدُّنْيَا نَمُوتُ وَنَحْيَا وَمَا يُهْلِكُنَآ إِلَّا ٱلدَّهْرُ ۚ وَمَا لَهُم بِذَٰلِكَ مِنْ عِلْمٍ ۖ إِنْ هُمْ إِلَّا يَظُنُّونَ", transliteration: "Waqaloo ma hiya illa hayatuna alddunya namootu wanahya wama yuhlikuna illa alddahru wama lahum bithalika min AAilmin in hum illa yathunnoona", transliterationB: "Wa qaaloo maa hiya illaa hayaatunad dunyaa namootu wa nahyaa wa maa yuhlikunaaa illad dahr; wa maa lahum bizaalika min 'ilmin in hum illaayazunnoon", english: "And they say: \"What is there but our life in this world? We shall die and we live, and nothing but time can destroy us.\" But of that they have no knowledge: they merely conjecture", romanUrdu: "Yeh log kehte hain ke “zindagi bas yahi hamari duniya ki zindagi hai, yahin hamara marna aur jeena hai aur gardish-e-ayyam ( passage of time) ke siwa koi cheez nahin ho humein halaak karti ho.” Dar haqeeqat is maamle mein inke paas koi ilm nahin hai yeh mehaz gumaan ki bina par yeh baatein karte hain" },
    { number: 25, arabic: "وَإِذَا تُتْلَىٰ عَلَيْهِمْ ءَايَٰتُنَا بَيِّنَٰتٍۢ مَّا كَانَ حُجَّتَهُمْ إِلَّآ أَن قَالُوا۟ ٱئْتُوا۟ بِـَٔابَآئِنَآ إِن كُنتُمْ صَٰدِقِينَ", transliteration: "Waitha tutla AAalayhim ayatuna bayyinatin ma kana hujjatahum illa an qaloo itoo biabaina in kuntum sadiqeena", transliterationB: "Wa izaa tutlaa 'alaihim aayaatuna baiyinaatim maa kaana hujjatahum illaaa an qaalu'too bi aabaaa'inaaa in kuntum saadiqeen", english: "And when Our Clear Signs are rehearsed to them their argument is nothing but this: They say, \"Bring (back) our forefathers, if what ye say is true", romanUrdu: "Aur jab hamari wazeh aayat unhein sunayi jaati hain to inke paas koi hujjat iske siwa nahin hoti ke utha lao hamare baap dada ko agar tum sacche ho" },
    { number: 26, arabic: "قُلِ ٱللَّهُ يُحْيِيكُمْ ثُمَّ يُمِيتُكُمْ ثُمَّ يَجْمَعُكُمْ إِلَىٰ يَوْمِ ٱلْقِيَٰمَةِ لَا رَيْبَ فِيهِ وَلَٰكِنَّ أَكْثَرَ ٱلنَّاسِ لَا يَعْلَمُونَ", transliteration: "Quli Allahu yuhyeekum thumma yumeetukum thumma yajmaAAukum ila yawmi alqiyamati la rayba feehi walakinna akthara alnnasi la yaAAlamoona", transliterationB: "Qulil laahu yuhyeekum summa yumeetukum summa yajma'ukum ilaa Yawmil Qiyaamati laa raiba feehi wa laakinna aksaran naasi laa ya'lamoon", english: "Say: \"It is Allah Who gives you life, then gives you death; then He will gather you together for the Day of Judgment about which there is no doubt\": But most men do not understand", romanUrdu: "Aey Nabi insey kaho Allah hi tumhein zindagi bakashta hai, phir wahi tumhein maut deta hai , phir wahi tumko us qayamat ke din jamaa karega jiske aane mein koi shakk nahin. Magar aksar log jaante nahin hain" },
    { number: 27, arabic: "وَلِلَّهِ مُلْكُ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۚ وَيَوْمَ تَقُومُ ٱلسَّاعَةُ يَوْمَئِذٍۢ يَخْسَرُ ٱلْمُبْطِلُونَ", transliteration: "Walillahi mulku alssamawati waalardi wayawma taqoomu alssaAAatu yawmaithin yakhsaru almubtiloona", transliterationB: "Wa lillaahi mulkus samaawaati wal ard; wa Yawma taqoomus Saa'atu Yawma 'iziny yakhsarul mubtiloon", english: "To Allah belongs the dominion of the heavens and the earth, and the Day that the Hour of Judgment is established,- that Day will the dealers in Falsehood perish", romanUrdu: "Zameen aur aasmaano ki badshahi Allah hi ki hai, aur jis roz qayamat ki ghadi aa khadi hogi us din baatil parast khasarey (nuksan) mein padh jayenge" },
    { number: 28, arabic: "وَتَرَىٰ كُلَّ أُمَّةٍۢ جَاثِيَةًۭ ۚ كُلُّ أُمَّةٍۢ تُدْعَىٰٓ إِلَىٰ كِتَٰبِهَا ٱلْيَوْمَ تُجْزَوْنَ مَا كُنتُمْ تَعْمَلُونَ", transliteration: "Watara kulla ommatin jathiyatan kullu ommatin tudAAa ila kitabiha alyawma tujzawna ma kuntum taAAmaloona", transliterationB: "Wa taraa kulla ummatin jaasiyah; kullu ummatin tud'aaa ilaa kitaabihaa al Yawma tujzawna maa kuntum ta'maloon", english: "And thou wilt see every sect bowing the knee: Every sect will be called to its Record: \"This Day shall ye be recompensed for all that ye did", romanUrdu: "Us waqt tum har girooh ko ghuthano (knees) ke bal gira dekhoge. Har girooh ko pukara jayega ke aaye aur apna naame aamal dekhe. Unse kaha jayega: “aaj tum logon ko un aamal ka badla diya jayega jo tum karte rahe thay" },
    { number: 29, arabic: "هَٰذَا كِتَٰبُنَا يَنطِقُ عَلَيْكُم بِٱلْحَقِّ ۚ إِنَّا كُنَّا نَسْتَنسِخُ مَا كُنتُمْ تَعْمَلُونَ", transliteration: "Hatha kitabuna yantiqu AAalaykum bialhaqqi inna kunna nastansikhu ma kuntum taAAmaloona", transliterationB: "Haazaa kitaabunaa yantiqu 'alaikum bilhaqq; innaa kunnaa nastansikhu maa kuntum ta'maloon", english: "This Our Record speaks about you with truth: For We were wont to put on Record all that ye did", romanUrdu: "Yeh hamara tayyar karaya hua aamal naama hai jo tumhare upar theek theek shahadat de raha hai, jo kuch bhi tum karte thay usey hum likhwate ja rahe thay”" },
    { number: 30, arabic: "فَأَمَّا ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ فَيُدْخِلُهُمْ رَبُّهُمْ فِى رَحْمَتِهِۦ ۚ ذَٰلِكَ هُوَ ٱلْفَوْزُ ٱلْمُبِينُ", transliteration: "Faamma allatheena amanoo waAAamiloo alssalihati fayudkhiluhum rabbuhum fee rahmatihi thalika huwa alfawzu almubeenu", transliterationB: "Fa ammal lazeena aamaanoo wa 'amilus saalihaati fayudkhiluhum Rabbuhum fee rahmatih; zaalika huwal fawzul mubeen", english: "Then, as to those who believed and did righteous deeds, their Lord will admit them to His Mercy that will be the achievement for all to see", romanUrdu: "Phir jo log imaan laaye thay aur neik aamal karte rahey thay unhein unka Rubb apni rehmat mein dakhil karega. Aur yahi sareeh kaamiyabi hai" },
    { number: 31, arabic: "وَأَمَّا ٱلَّذِينَ كَفَرُوٓا۟ أَفَلَمْ تَكُنْ ءَايَٰتِى تُتْلَىٰ عَلَيْكُمْ فَٱسْتَكْبَرْتُمْ وَكُنتُمْ قَوْمًۭا مُّجْرِمِينَ", transliteration: "Waamma allatheena kafaroo afalam takun ayatee tutla AAalaykum faistakbartum wakuntum qawman mujrimeena", transliterationB: "Wa ammal lazeena kafarooo afalam takun Aayaatee tutlaa 'alaikum fastakbartum wa kuntum qawmam mujrimeen", english: "But as to those who rejected Allah, (to them will be said): \"Were not Our Signs rehearsed to you? But ye were arrogant, and were a people given to sin", romanUrdu: "Aur jin logon ne kufr kiya tha unsey kaha jayega “kya meri aayat tumko nahin sunayi jaati thin? Magar tumne takabbur kiya aur mujrim bankar rahey" },
    { number: 32, arabic: "وَإِذَا قِيلَ إِنَّ وَعْدَ ٱللَّهِ حَقٌّۭ وَٱلسَّاعَةُ لَا رَيْبَ فِيهَا قُلْتُم مَّا نَدْرِى مَا ٱلسَّاعَةُ إِن نَّظُنُّ إِلَّا ظَنًّۭا وَمَا نَحْنُ بِمُسْتَيْقِنِينَ", transliteration: "Waitha qeela inna waAAda Allahi haqqun waalssaAAatu la rayba feeha qultum ma nadree ma alssaAAatu in nathunnu illa thannan wama nahnu bimustayqineena", transliterationB: "Wa izaa qeela inna wa'dallaahi haqqunw was Saa'atu laa raiba feehaa qultum maa nadree mas Saa'atu in nazunnu illaa zannanw wa maa nahnu bimustaiqineen", english: "And when it was said that the promise of Allah was true, and that the Hour- there was no doubt about its (coming), ye used to say, 'We know not what is the hour: we only think it is an idea, and we have no firm assurance", romanUrdu: "Aur jab kaha jaata tha ke Allah ka waada bar- haqq hai aur qayamat ke aane mein koi shakk nahin, to tum kehte thay ke hum nahin jaante qayamat kya hoti hai, hum to bas ek gumaan sa rakhte hain , yaqeen hum ko nahin hai”" },
    { number: 33, arabic: "وَبَدَا لَهُمْ سَيِّـَٔاتُ مَا عَمِلُوا۟ وَحَاقَ بِهِم مَّا كَانُوا۟ بِهِۦ يَسْتَهْزِءُونَ", transliteration: "Wabada lahum sayyiatu ma AAamiloo wahaqa bihim ma kanoo bihi yastahzioona", transliterationB: "Wa badaa lahum saiyiaatu maa 'amiloo wa haaqa bihim maa kaanoo bihee yastahzi'oon", english: "Then will appear to them the evil (fruits) of what they did, and they will be completely encircled by that which they used to mock at", romanUrdu: "Us waqt unpar unke aamal ki buraiyan khul jayengi aur woh usi cheez ke pher mein aa jayenge jiska woh mazaak udaya karte thay" },
    { number: 34, arabic: "وَقِيلَ ٱلْيَوْمَ نَنسَىٰكُمْ كَمَا نَسِيتُمْ لِقَآءَ يَوْمِكُمْ هَٰذَا وَمَأْوَىٰكُمُ ٱلنَّارُ وَمَا لَكُم مِّن نَّٰصِرِينَ", transliteration: "Waqeela alyawma nansakum kama naseetum liqaa yawmikum hatha wamawakumu alnnaru wama lakum min nasireena", transliterationB: "Wa qeelal yawma nansaakum kamaa naseetum liqaaa'a yawmikum haazaa wa maawaakumun Naaru wa maa lakum min naasireen", english: "It will also be said: \"This Day We will forget you as ye forgot the meeting of this Day of yours! and your abode is the Fire, and no helpers have ye", romanUrdu: "Aur insey kehdiya jayega ke “Aaj hum bhi usi tarah tumhein bhulaye detay hain jis tarah tum is din ki mulaqaat ko bhool gaye thay.Tumhara thikana ab dozakh hai aur koi tumhari madad karne wala nahin hai" },
    { number: 35, arabic: "ذَٰلِكُم بِأَنَّكُمُ ٱتَّخَذْتُمْ ءَايَٰتِ ٱللَّهِ هُزُوًۭا وَغَرَّتْكُمُ ٱلْحَيَوٰةُ ٱلدُّنْيَا ۚ فَٱلْيَوْمَ لَا يُخْرَجُونَ مِنْهَا وَلَا هُمْ يُسْتَعْتَبُونَ", transliteration: "Thalikum biannakumu ittakhathtum ayati Allahi huzuwan wagharratkumu alhayatu alddunya faalyawma la yukhrajoona minha wala hum yustaAAtaboona", transliterationB: "Zaalikum bi annakumut takhaztum aayaatil laahi huzuwanw wa gharratkumul hayaatud dunyaa; fal yawma laa yukhrajoona minhaa wa laahum yusta'taboon", english: "This, because ye used to take the Signs of Allah in jest, and the life of the world deceived you:\" (From) that Day, therefore, they shall not be taken out thence, nor shall they be received into Grace", romanUrdu: "Yeh tumhara anjaam is liye hua hai ke tumne Allah ki aayat ka mazaak bana liya tha aur tumhein duniya ki zindagi ne dhoke mein daal diya tha. Lihaza aaj na yeh log dozakh se nikale jayenge aur na inse kaha jayega ke maafi maang kar apne Rubb ko raazi karo”" },
    { number: 36, arabic: "فَلِلَّهِ ٱلْحَمْدُ رَبِّ ٱلسَّمَٰوَٰتِ وَرَبِّ ٱلْأَرْضِ رَبِّ ٱلْعَٰلَمِينَ", transliteration: "Falillahi alhamdu rabbi alssamawati warabbi alardi rabbi alAAalameena", transliterationB: "Falillaahil hamdu Rabbis samaawaati wa Rabbil ardi Rabbil-'aalameen", english: "Then Praise be to Allah, Lord of the heavens and Lord of the earth,- Lord and Cherisher of all the Worlds", romanUrdu: "Pas taarif Allah hi ke liye hai jo zameen aur aasmaano ka maalik aur saare jahan waalon ka parwardigar hai" },
    { number: 37, arabic: "وَلَهُ ٱلْكِبْرِيَآءُ فِى ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۖ وَهُوَ ٱلْعَزِيزُ ٱلْحَكِيمُ", transliteration: "Walahu alkibriyao fee alssamawati waalardi wahuwa alAAazeezu alhakeemu", transliterationB: "Wa lahul kibriyaaa'u fissamaawaati wal ardi wa Huwal 'Azeezul Hakeem", english: "To Him be glory throughout the heavens and the earth: and He is Exalted in Power, Full of Wisdom", romanUrdu: "Zameen aur aasmaano mein badayi usi ke liye hai aur wahi zabardast (most mighty) aur daana(most wise) hai" }
  ]
};
